INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('13bc612c-9c6b-52cb-acc2-d3c84af8c34d', '5b9ee761-7aa7-4379-bab3-faf4fd11f223', 'Many diverse cultures and ancient civilizations originated in ___, the largest continent on Earth.', '許多多樣化的文化與古老文明都起源於亞洲，這是世界上最大的洲。', 'Asia', 'Africa', 'Europe', 'America', 'Asia 為地理專有名詞，指亞洲。在英文寫作中，所有地名與大洲名首字母皆須大寫。', 'Asia 讀音類似「愛西亞」，可以聯想亞洲是個充滿多樣文化魅力的廣大洲。', '2026-07-07 00:41:29', '2026-07-07 00:41:29'),
('67fcc887-dbab-51c1-8d38-3d73dc0d14d9', 'a3c99a9f-b67c-49b8-b9e0-7562df5d815d', 'In English grammar, an ___ is a word that describes or modifies a noun.', '在英文語法中，___ 是用來描述或修飾名詞的字。', 'adjective', 'adverb', 'article', 'object', 'ad (向/趨向) + ject (投/丟) → 投向名詞以增加其描述特質。', 'ad (向) + ject (丟) → 把特質『丟』到名詞身上，用來形容名詞的字就是形容詞。', '2026-07-06 17:44:59', '2026-07-06 17:44:59'),
('02bf457a-aa19-533f-a487-0e859ab3eecd', '98b02201-7ded-4a72-bf46-d29d6eb19745', 'With the shift to digital platforms, every large ___ must rethink how they reach their target audience.', '隨著向數位平台的轉型，每一位大型登廣告者都必須重新思考如何接觸他們的目標受眾。', 'advertiser', 'consumer', 'competitor', 'investor', 'ad (向/對) + vert (轉) + ise (動詞化) + er (人) → 將資訊轉向大眾的人。', 'ad (廣告) + vert (轉) + er (人) → 把產品資訊轉向大眾的人 → 登廣告者。', '2026-07-06 18:13:39', '2026-07-06 18:13:39'),
('4d94205d-3d14-51b8-b4f4-28c0ce1ad2e9', '844b8166-e422-4437-a34b-847f0bbac78e', 'If you are struggling with your career choices, you should seek professional ___ from a counselor.', '如果你在職業選擇上感到掙扎，你應該向諮商師尋求專業的忠告。', 'advice', 'warning', 'promise', 'request', 'ad 表示向，vis 表示看，字面意思是朝著某個情況去看，進而提供指引。', '記住 advice 是名詞，常與 seek 或 give 連用，例如 seek advice 尋求建議。', '2026-07-06 18:14:18', '2026-07-06 18:14:18'),
('2e55a21d-20e9-5e88-aade-393a130ed0d9', '2e8d6a52-2382-473f-8ff4-328570909ea0', 'The local sports club is an ___ of the national athletic association.', '這間地方運動俱樂部是國家田徑協會的一個成員組織。', 'affiliate', 'celebrity', 'merchant', 'resident', 'af- (趨向) + fili (兒子/成員) → 趨向於成為某個組織的成員。', '想像加入一個組織就像是分支出去的小成員 (fili 聯想到 filial 孝順的，指與家庭成員的關係)。', '2026-07-06 18:26:49', '2026-07-06 18:26:49'),
('a953ac66-06b5-52ee-b16b-ec98a4ea9db1', '5b856ddc-94f8-45df-ab42-02b605c48bc7', 'In high school math, ___ is the branch of mathematics where symbols and letters are used to represent numbers in equations.', '在高中數學中，代數是數學的一個分支，其中使用符號和字母在方程式中代表數字。', 'algebra', 'geometry', 'statistics', 'calculus', '來自阿拉伯語 al-jabr，意指重新組合或恢復平衡。', '記住 algebra 經常與含有 x 或 y 的方程式聯繫在一起。', '2026-07-06 19:46:09', '2026-07-06 19:46:09'),
('2890858a-4f60-5728-aa05-26b850949e25', 'f48125b6-024a-46ae-8675-480e00607f4c', 'Will you ___ me to use your computer for a moment?', '你可以允許我用一下你的電腦嗎？', 'allow', 'tell', 'help', 'ask', 'al (向) + low (law 法律) → 趨向規則 → 允許', '想像說：『阿囉 (allow)！你可以用我的電腦！』來幫助記憶。', '2026-07-06 13:46:25', '2026-07-06 13:46:25'),
('a3ce64fc-f388-5ad2-8d16-5edb05d6194d', '68e5cdc6-3332-48dc-b308-bdebbedf1587', 'It was ___ dark outside.', '外面___天黑了。', 'almost', 'surely', 'carefully', 'happily', 'almost 表示「接近某種程度」，在句中修飾形容詞 dark。', 'almost → 幾乎，表示事情快要發生或狀態快要達到。', '2026-07-06 13:47:23', '2026-07-06 13:47:23'),
('d0953a8b-08ad-5a35-82dd-869d08ddf035', '82810b1d-8eca-48b1-838c-bafd9046bd0c', 'A small ___ is flying near the cave at night.', '一隻小蝙蝠在晚上飛向洞穴附近。', 'bat', 'bird', 'moth', 'bee', '此單字為基礎單字，名詞可指「蝙蝠」或「球棒」。', '想像蝙蝠 (bat) 在黑夜中飛行的樣子。', '2026-07-07 02:35:23', '2026-07-07 02:35:23'),
('5eade547-c731-547f-8d92-b48e61fefdfd', 'e8e48471-3a64-4399-8599-14c3f4ae316f', 'The ___ wears a suit and works in a big office.', '那位商人穿著西裝，在一家大辦公室工作。', 'businessman', 'doctor', 'driver', 'teacher', '由 business (商業) 與 man (男人) 組成。', 'business (生意) + man (人) → 商人', '2026-07-07 09:02:34', '2026-07-07 09:02:34'),
('0faf5dad-cc38-51fa-be9b-b5e9fecbc59d', 'f6f44939-1a9a-4d37-a949-659f30df3c78', 'She had to make a difficult ___ between the two jobs.', '她必須在兩份工作之間做出一個困難的選擇。', 'choice', 'mistake', 'promise', 'noise', 'choice 為名詞，由動詞 choose (選擇) 變化而來。', '記住 choose 是動作 (動詞) → choice 是結果 (名詞)。', '2026-07-07 03:51:51', '2026-07-07 03:51:51'),
('cddd6025-2198-53e8-b6b6-6768f0f871dd', 'd13e0c15-0e9d-4ea7-8c8b-19c4303d008f', 'The baby has very ___ cheeks.', '這個寶寶有著非常圓胖的臉頰。', 'chubby', 'angry', 'hungry', 'brave', 'chubby 為形容詞，用來形容嬰兒或小孩肉嘟嘟、圓胖的樣子。', '想像胖小孩走一步很慢：chubby → 胖嘟嘟。', '2026-07-07 03:57:57', '2026-07-07 03:57:57'),
('6994c961-27b3-5d97-9f89-64b0e630ed11', '04389d35-ea87-480c-a713-6645e0683753', 'I want to buy a special gift for my ___ on his birthday.', '我想在我的父親生日時送他一份特別的禮物。', 'dad', 'chef', 'singer', 'driver', 'dad 為「父親」的非正式口語說法，正式用法為 father。', 'dad 的發音短促，就像在叫爸爸時發出的親切聲音。', '2026-07-07 02:36:19', '2026-07-07 02:36:19'),
('c675b21b-b949-50c3-b0f7-5f1ac91bff9d', '5e767169-2c20-400a-b068-5b0d10f7fd45', '___ you like English?', '你喜歡英文嗎？', 'Do', 'Are', 'Have', 'Was', 'do (用來構成疑問句)', 'Do + 主詞 + 動詞原形? (疑問句結構)', '2026-07-05 08:35:16', '2026-07-05 08:35:16'),
('dd747573-1ddc-5d26-9918-4659c9c8c8a1', '60adc378-9e4d-40f8-9d01-06242df3f9e3', 'She drew a small black ___ on the paper.', '她在紙上畫了一個黑色的小圓點。', 'dot', 'line', 'box', 'star', 'dot 為名詞，指一個微小的圓點。', '聯想句號 . 的形狀，它就是一個小點點 (dot)。', '2026-07-07 05:16:18', '2026-07-07 05:16:18'),
('8f8cdc01-cbb0-54af-91f6-4bd709ca81a9', '920ea502-182e-47ee-afc2-b246434540ce', 'Please don''t ___ me by asking such personal questions.', '請不要問這些私人問題來讓我感到困窘。', 'embarrass', 'help', 'teach', 'follow', 'em- (使...) + bar (障礙) → 使事情變得不順利或難堪。', '想像在眾人面前 (bar) 遇到困難，會讓你感到很 embarrass (困窘)。', '2026-07-07 03:42:17', '2026-07-07 03:42:17'),
('ffbee372-ddd0-5fd1-8c29-ed4fa73a715d', '3ce8146c-5b29-477f-b5fa-17160e99e037', 'The movie is about an ___ king who wants to hurt people.', '這部電影是關於一個想要傷害別人的邪惡國王。', 'evil', 'angry', 'old', 'eager', 'evil 為單字，形容詞意為「邪惡的」，名詞意為「邪惡」。', '記住 evil → 邪惡。想像電影裡的壞人都在做 evil 的事。', '2026-07-07 04:56:39', '2026-07-07 04:56:39'),
('c299a5ac-c98d-5c17-86a1-cef0f95d2e25', '62636026-0251-407c-87f0-5f5233f0ce21', 'Who is your ___ singer?', '誰是你最喜歡的歌手？', 'favorite', 'famous', 'tall', 'slow', 'root: favor (偏愛) + suffix: -ite (形成形容詞/名詞)', 'favor (好感) + ite → favorite (最喜愛的)', '2026-07-07 05:16:25', '2026-07-07 05:16:25'),
('ca859ec5-6546-59fe-93ee-cd5a17b4714d', '91dcf5ec-a9de-490b-a4f5-84248a8f2fa9', 'The professor explained the theory so clearly that ___ was able to grasp the complex concept immediately.', '教授對該理論的解釋非常清晰，以至於他能夠立即掌握這個複雜的概念。', 'he', 'we', 'you', 'I', '第三人稱單數陽性代名詞。', '指代特定的男性單數個體 → 使用 he。', '2026-07-06 10:50:11', '2026-07-06 10:50:11'),
('e5d9b3e1-420c-5326-a4d5-85305602d955', 'f3b99ae4-87be-4a8b-ae89-45144f380d7e', 'In recent years, more and more ___ have started using social media for news.', '近年來，越來越多的人開始使用社群媒體來獲取新聞。', 'people', 'plants', 'tools', 'clouds', 'people 作為名詞，代表「人們」這個群體。', 'people (人們) 都在用手機看新聞。', '2026-07-06 10:54:28', '2026-07-06 10:54:28'),
('72c228ab-de79-5d96-aba9-eab3387e61e1', '4d1fc80d-30d2-4fef-9ffa-9473c55eef51', 'You should ___ the opportunity to study abroad if you have the chance.', '如果你有機會，你應該把握留學的機會。', 'take', 'make', 'give', 'do', 'take 在此表示 把握、利用。', '把機會當作一件東西，趕快「拿」住它。', '2026-07-05 08:08:19', '2026-07-05 08:08:19'),
('56d45062-49d5-5bbc-a4a3-22e745cda875', 'fe4aaa4a-529d-4865-94e8-958903d9469a', 'The city council decided to ___ the downtown area into residential and commercial sectors to better manage urban growth.', '市議會決定將市中心劃分為住宅區與商業區，以便更好地管理城市成長。', 'zone', 'grant', 'judge', 'notice', 'zone 原意指帶狀物，引申為劃分特定區域。', '想像把土地像皮帶一樣「分區」圍起來。', '2026-07-06 09:53:19', '2026-07-06 09:53:19');
